from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # Group triples by their subject to avoid repeating the subject in every clause
    from collections import defaultdict

    subject_map: dict[str, list[tuple[str, str]]] = defaultdict(list)
    for t in triples:
        subject_map[t.subject].append((t.predicate, t.object))

    sentences: list[str] = []

    for subj, po_list in subject_map.items():
        fragments: list[str] = []
        for p, o in po_list:
            # map each predicate to a concise fragment (without repeating the subject)
            if p == "birthDate":
                frag = f"was born on {o}"
            elif p == "birthYear":
                frag = f"was born in {o}"
            elif p == "birthPlace":
                frag = f"was born in {o}"
            elif p == "deathDate":
                frag = f"died on {o}"
            elif p == "deathPlace":
                frag = f"died in {o}"
            elif p == "origin":
                frag = f"originates from {o}"
            elif p == "background":
                frag = f"is a {o}"
            elif p == "genre":
                frag = f"is known for {o} music"
            elif p == "instrument":
                frag = f"plays the {o}"
            elif p == "occupation":
                frag = f"works as {o}"
            elif p == "associatedBand/associatedMusicalArtist":
                frag = f"is associated with {o}"
            elif p == "recordLabel":
                frag = f"is signed to {o}"
            elif p == "activeYearsStartYear":
                frag = f"started their career in {o}"
            elif p == "activeYearsEndYear":
                frag = f"ended their career in {o}"
            elif p == "nationality":
                frag = f"is {o}"
            elif p == "capital":
                frag = f"is the capital of {o}"
            elif p == "country":
                frag = f"is located in {o}"
            elif p == "isPartOf":
                frag = f"is part of {o}"
            elif p in {"language", "officialLanguage"}:
                frag = f"has language {o}"
            else:
                frag = f"{p} {o}"
            fragments.append(frag)

        # Join fragments into a single fluent clause for this subject
        if fragments:
            sentence = f"{subj} " + ", ".join(fragments) + "."
        else:
            sentence = f"{subj}."
        sentences.append(sentence)

    # Combine sentences for different subjects into the final output
    return " ".join(sentences)

# EVOLVE-BLOCK-END

